  ('generalpolice-94737317-moex-00232', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '甲員警利用職務上之權力與機會，在取締性交易場所時，強制猥褻店內的應召女子，請問甲除了觸犯刑法 第224條強制猥褻罪外，還應另以何條論處？', '["刑法第134條之公務員加重處罰規定", "刑法第121條之職務行為受賄罪", "刑法第122條之違背職務受賄罪", "刑法第131條之圖利罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00233', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '雇主若欲以勞工對於所擔任之工作確不能勝任，終止勞動契約，應依勞動基準法規定辦理。下列敘述何者 錯誤？', '["應依第16條之預告期間規定，預告終止勞動契約", "雇主應自知悉勞工對於所擔任之工作確不能勝任情形之日起，30日內終止勞動契約", "應依第17條之資遣費規定，給付勞工資遣費", "雇主應使勞工於工作時間得請假外出另謀工作，請假時數每星期不得超過 2 日之工作時間，請假期間 之工資照給"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00234', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '入出國及移民法第58條第2項規定：「跨國（境）婚姻媒合不得要求或期約報酬。」違反該條者，同法 並設有罰則。依據大法官解釋意旨，下列敘述何者錯誤？', '["形同禁止跨國婚姻媒合工作及業務之職業，目的與手段間應具有實質關聯性", "管制目的在保障結婚當事人權益、防杜人口販運及避免物化女性，合憲", "管制手段並未禁止被媒合者於媒合成功後主動致贈金錢或財產上利益予媒合者，合憲", "對於非跨國婚姻媒合，並未禁止要求或期約報酬，屬於合理的差別待遇，合憲"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00235', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '依公民投票法之規定，下列何者為可以公投之事項？', '["對直轄市的年度預算案進行複決", "對法官是否應享有終身俸進行複決", "對國家重大公共建設規劃方向提出創制", "就廢除奢侈稅進行創制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00236', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '有關犯罪之法律效果，下列敘述何者錯誤？', '["刑分主刑與從刑，從刑為褫奪公權", "褫奪公權之宣告，自裁判確定時發生效力", "沒收不屬於主刑，亦不屬於從刑", "宣告死刑或無期徒刑者，得不宣告褫奪公權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00237', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '甲和乙擬設立一家股份有限公司，故請教律師現今公司法規定相關問題，請問下列敘述何者正確？', '["公司得同時發行票面金額股及無票面金額股", "股東之出資除以現金外，也得以公司所需財產、技術抵充之", "非公開發行公司發行有票面金額股股票，發行之價格得低於票面金額", "閉鎖型股份有限公司得接受信用出資"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00238', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '依憲法訴訟法規定，下列何者並非憲法法庭審理之案件類型？', '["裁判憲法審查案件", "總統、副總統罷免案件", "地方自治保障案件", "統一解釋法律及命令案件"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00239', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '下列何種請求權不適用消滅時效之規定？', '["侵權行為之損害賠償請求權", "房屋租金給付請求權", "已登記不動產所有人之回復請求權", "扶養費給付請求權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00240', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '關於法律行為，下列敘述何者正確？', '["法律行為，有背於公共秩序或善良風俗者，無效", "法律行為，違反強制或禁止之規定者，應向法院聲請撤銷，尚未撤銷判決確定前，其效力未定", "法律行為，不依法定方式者，應向法院聲請撤銷，尚未撤銷判決確定前，其效力未定", "法律行為，係乘他人之急迫、輕率或無經驗，使其為財產上之給付或為給付之約定，依當時情形顯失公 平者，應向法院於該行為發生後兩年內，聲請撤銷，尚未撤銷判決確定前，其效力未定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00241', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-3d2b73b6', 'sub-generalpolice-94737317-03', NULL, 'single_choice', '依憲法與原住民族基本法，下列敘述何者正確？', '["政府與原住民族自治間權限發生爭議時，由總統府召開協商會議決定之", "憲法所稱之法律，謂經司法院通過，由立法院公布之法律", "法律與憲法有無牴觸發生疑義時，由立法院聲請最高法院解釋之", "命令與憲法或法律牴觸者，於不違背公共秩序或善良風俗者，為有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "3592102ee95e", "answer_pdf_sha1": "de274672e5dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
